// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.JoinFactor;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.JoinRegion;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.JoinSearchDependencyStamp;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.MemoJoinRegionExtractor;
import org.junit.jupiter.api.Test;

class CascadesJoinSubscriptionTest {

	@Test
	void sameRegionRetainsEverySourceExpressionSubscription() {
		int rootGroupId = 50;
		JoinRegion region = new JoinRegion(List.of(new JoinFactor(0, 30), new JoinFactor(1, 40)), List.of());
		WinnerKey goalKey = new WinnerKey(rootGroupId, PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS,
				OptimizationGoal.CostPolicy.EXACT);
		CascadesPlanner.JoinWorkKey sharedKey = new CascadesPlanner.JoinWorkKey(rootGroupId, region.identity(), goalKey,
				0L, JoinSearchDependencyStamp.EMPTY);
		CascadesPlanner.JoinWork firstSource = new CascadesPlanner.JoinWork(sharedKey, 101,
				extraction(region, Set.of(rootGroupId, 10), Set.of(30, 40)), "test_group_change");
		CascadesPlanner.JoinWork secondSource = new CascadesPlanner.JoinWork(sharedKey, 202,
				extraction(region, Set.of(rootGroupId, 20), Set.of(30, 40)), "test_group_change");
		CascadesPlanner.SearchState state = new CascadesPlanner.SearchState(0,
				OptimizationGoal.SearchMode.EXACT);

		state.enqueueJoinWork(firstSource);
		state.enqueueJoinWork(secondSource);

		assertThat(state.subscribedJoinSourceExpressions(10)).containsExactly(101);
		assertThat(state.subscribedJoinSourceExpressions(20)).containsExactly(202);
		assertThat(state.subscribedJoinSourceExpressions(30)).containsExactly(101, 202);
		assertThat(state.subscribedJoinSourceExpressions(40)).containsExactly(101, 202);
		assertThat(state.subscribedJoinSourceExpressions(rootGroupId)).containsExactly(101, 202);
		assertThat(state.subscribedJoinSourceExpressions(999)).isEmpty();
	}

	private static MemoJoinRegionExtractor.Result extraction(JoinRegion region, Set<Integer> expandedGroupIds,
			Set<Integer> leafGroupIds) {
		return new MemoJoinRegionExtractor.Result(MemoJoinRegionExtractor.Status.EXTRACTED, region,
				region.identity(), expandedGroupIds, leafGroupIds, List.of());
	}

}
